func (c *Client) Use(mws ...Middleware) {
	// Put the original middlewares to the first
	middlewares := make([]Middleware, 0, 1+len(mws))
	if c.mws != nil {
		middlewares = append(middlewares, c.mws)
	}
	middlewares = append(middlewares, mws...)
	c.mws = chain(middlewares...)
}

// UseAsLast is used to add middleware to the end of the middleware chain.
//
// Will return an error if last middleware has been set before, to ensure all middleware has the change to work,
// Please use `TakeOutLastMiddleware` to take out the already set middleware.
// Chain the middleware after or before is both Okay - but remember to put it back.
func (c *Client) UseAsLast(mw Middleware) error {
	if c.lastMiddleware != nil {
		return errorLastMiddlewareExist
	}
	c.lastMiddleware = mw
	return nil
}

// TakeOutLastMiddleware will return the set middleware and remove it from client.
//
// Remember to set it back after chain it with other middleware.
func (c *Client) TakeOutLastMiddleware() Middleware {
	last := c.lastMiddleware
	c.lastMiddleware = nil
	return last
}

func handleOAuthSuccess(
	c *gin.Context,
	authMiddleware *jwt.GinJWTMiddleware,
	user *User,
	provider string,
) error {
	// Set user identity in context (for middleware callbacks)
	c.Set(authMiddleware.IdentityKey, user)
	c.Set("oauth_provider", provider)

	// Generate JWT token
	token, err := authMiddleware.TokenGenerator(c.Request.Context(), user)
	if err != nil {
		return err
	}

	// Set cookies (both access token and refresh token)
	authMiddleware.SetCookie(c, token.AccessToken)
	authMiddleware.SetRefreshTokenCookie(c, token.RefreshToken)

	// Let gin-jwt handle everything (cookies, headers, response) via LoginResponse
	// The middleware will automatically:
	// - Set httpOnly cookie (if SendCookie is enabled)
	// - Set Authorization header (if SendAuthorization is enabled)
	// - Call LoginResponse callback (defined in initJWTParams)
	if authMiddleware.LoginResponse != nil {
		authMiddleware.LoginResponse(c, token)
	}

	return nil
}

backtrackToNextNodeKind := func(fromKind kind) (nextNodeKind kind, valid bool) {
	previous := currentNode
	currentNode = previous.parent
	valid = currentNode != nil

	// Next node type by priority
	if previous.kind == anyKind {
		nextNodeKind = staticKind
	} else {
		nextNodeKind = previous.kind + 1
	}

	if fromKind == staticKind {
		// when backtracking is done from static kind block we did not change search so nothing to restore
		return
	}

	// restore search to value it was before we move to current node we are backtracking from.
	if previous.kind == staticKind {
		searchIndex -= len(previous.prefix)
	} else {
		paramIndex--
		// for param/any node.prefix value is always `:` so we can not deduce searchIndex from that and must use pValue
		// for that index as it would also contain part of path we cut off before moving into node we are backtracking from
		searchIndex -= len(pathValues[paramIndex].Value)
		pathValues[paramIndex].Value = ""
	}
	search = path[searchIndex:]
	return
}

func NewConditionalHandler(filter Filter, handlers ...Handler) Handler {
	return func(ctx *Context) {
		if filter(ctx) {
			// Note that we don't want just to fire the incoming handlers, we must make sure
			// that it won't break any further handler chain
			// information that may be required for the next handlers.
			//
			// The below code makes sure that this conditional handler does not break
			// the ability that iris provides to its end-devs
			// to check and modify the per-request handlers chain at runtime.
			currIdx := ctx.HandlerIndex(-1)
			currHandlers := ctx.Handlers()

			if currIdx == len(currHandlers)-1 {
				// if this is the last handler of the chain
				// just add to the last the new handlers and call Next to fire those.
				ctx.AddHandler(handlers...)
				ctx.Next()
				return
			}
			// otherwise insert the new handlers in the middle of the current executed chain and the next chain.
			newHandlers := append(currHandlers[:currIdx+1], append(handlers, currHandlers[currIdx+1:]...)...)
			ctx.SetHandlers(newHandlers)
			ctx.Next()
			return
		}
		// if not pass, then just execute the next.
		ctx.Next()
	}
}

type RequestContext struct {
	conn     network.Conn
	Request  protocol.Request
	Response protocol.Response

	// Errors is a list of errors attached to all the handlers/middlewares who used this context.
	Errors errors.ErrorChain

	Params     param.Params
	handlers   HandlersChain
	fullPath   string
	index      int8
	HTMLRender render.HTMLRender

	// This mutex protect Keys map.
	mu sync.RWMutex

	// Keys is a key/value pair exclusively for the context of each request.
	Keys map[string]interface{}

	hijackHandler HijackHandler

	finishedMu sync.Mutex

	// finished means the request end.
	finished chan struct{}

	// traceInfo defines the trace information.
	traceInfo traceinfo.TraceInfo

	// enableTrace defines whether enable trace.
	enableTrace bool

	// clientIPFunc get client ip by use custom function.
	clientIPFunc ClientIP

	// clientIPFunc get form value by use custom function.
	formValueFunc FormValueFunc

	binder binding.Binder
	exiled bool
}

func refactorBuilderx(deprecated, replacement string, fn func(allow bool)) {
	switch builderxConfirm {
	case confirmAll:
		fn(true)
		return
	case confirmIgnore:
		fn(false)
		return
	}

	msg := fmt.Sprintf(`Detects a deprecated package in the source code,
Deprecated package: %q
Replacement package: %q
It's recommended to use the replacement package, do you want to replace?
['Y' for yes, 'N' for no, 'A' for all, 'I' for ignore]: `,
		deprecated, replacement)

	fmt.Print(color.Yellow.Render(msg))

	for {
		var in string
		fmt.Scanln(&in)
		switch {
		case strings.EqualFold(in, "Y"):
			fn(true)
			return
		case strings.EqualFold(in, "N"):
			fn(false)
			return
		case strings.EqualFold(in, "A"):
			fn(true)
			builderxConfirm = confirmAll
			return
		case strings.EqualFold(in, "I"):
			fn(false)
			builderxConfirm = confirmIgnore
			return
		default:
			console.Warning("['Y' for yes, 'N' for no, 'A' for all, 'I' for ignore]: ")
		}
	}
}

package goa

type (
	// InterceptorInfo contains information about the request shared between
	// all interceptors in the service chain. It provides access to the service name,
	// method name, the type of call the interceptor is handling (unary, streaming send,
	// or streaming receive), and the request payload.
	InterceptorInfo interface {
		// Service returns the name of the service handling the request.
		Service() string
		// Method returns the name of the method handling the request.
		Method() string
		// CallType returns the type of call the interceptor is handling.
		CallType() InterceptorCallType
		// RawPayload returns the raw payload of the request.
		RawPayload() any
	}

	// InterceptorCallType is the type of call the interceptor is handling
	InterceptorCallType int
)

const (
	// InterceptorUnary indicates the interceptor is handling a unary call
	InterceptorUnary InterceptorCallType = iota
	// InterceptorStreamingSend indicates the interceptor is handling a streaming Send
	InterceptorStreamingSend
	// InterceptorStreamingRecv indicates the interceptor is handling a streaming Recv
	InterceptorStreamingRecv
)
